#include "parlay/primitives.h" // Includes map, group_by, flatten, hash, etc.
#include <algorithm>          // For std::min, std::max

template <class T>
parlay::sequence<T> dedup(parlay::sequence<T> const &A) {
  // The baseline parlay::remove_duplicates is an excellent, highly-optimized
  // hash-based implementation. For small inputs, its overhead is minimal, and it's
  // hard to beat. A cutoff of 20,000 is a reasonable heuristic based on typical
  // performance of parallel algorithms, below which the overhead of our more
  // complex strategy is not worthwhile.
  if (A.size() < 20000) {
    return parlay::remove_duplicates(A);
  }

  // For larger inputs, we can outperform the baseline by using a two-level
  // hashing scheme. The default parlay::remove_duplicates uses a single large
  // concurrent hash table. On highly parallel machines, this can lead to memory
  // system contention as many cores try to access the same data structure.
  //
  // Our strategy is a classic parallel divide-and-conquer approach:
  // 1. Partition the input into many small, independent buckets based on the
  //    high-order bits of the elements' hash values. This is done using
  //    parlay::group_by_key, which is extremely fast for bulk processing as it
  //    is based on integer sorting and avoids atomic operations.
  // 2. In parallel, find the unique elements within each smaller bucket. We
  //    call parlay::remove_duplicates on each bucket. Since the buckets are
  //    small and processed independently, contention is eliminated, and data
  //    accesses are more cache-friendly.
  // 3. Concatenate the sequences of unique elements from each bucket.
  //
  // This approach trades the contention of a single large hash table for the
  // overhead of an extra pass to group the data. For large N on many cores,
  // this is a winning trade-off.

  // Determine the number of buckets. We want enough buckets to create sufficient
  // parallelism and keep individual buckets small, but not so many that the
  // overhead of managing them becomes too high.
  // The number of buckets is chosen to be proportional to the number of workers,
  // ensuring good load balancing, but is also limited based on the input size
  // to prevent buckets from becoming too small.
  size_t num_buckets = parlay::round_up_to_power_of_two(
      std::max(size_t{1}, std::min((size_t)A.size() / 2048, parlay::num_workers() * 16)));

  // 1. Assign elements to buckets.
  // We create a sequence of (bucket_index, element) pairs.
  // Using parlay::hash ensures a high-quality hash distribution.
  // The bitwise AND is a fast way to compute `hash % num_buckets` since
  // num_buckets is a power of two.
  auto bucketed_elements = parlay::map(A, [num_buckets](const T& x) {
    return std::make_pair(parlay::hash<T>{}(x) & (num_buckets - 1), x);
  });

  // 2. Group elements by bucket index.
  // parlay::group_by_key permutes the elements so that all elements belonging
  // to the same bucket are contiguous. It returns a sequence of
  // (bucket_index, sequence_of_elements) pairs.
  auto buckets = parlay::group_by_key(bucketed_elements);

  // 3. Remove duplicates within each bucket in parallel.
  // We apply parlay::remove_duplicates to each bucket's element sequence.
  // This is the "conquer" step, solving many small problems in parallel.
  auto unique_in_buckets = parlay::map(buckets, [](const auto& bucket) {
    return parlay::remove_duplicates(bucket.second);
  });

  // 4. Flatten the results.
  // parlay::flatten concatenates the sequence of sequences into our final
  // single-sequence result.
  return parlay::flatten(unique_in_buckets);
}

