#include "parlay/primitives.h"
#include "parlay/sequence.h"
#include "parlay/parallel.h"
#include "parlay/utilities.h"

#include <atomic>
#include <type_traits>

// Forward declarations for the SFINAE-based dispatch
template <class T, class Enable = void>
struct dedup_impl;

// Main entry point
template <class T>
parlay::sequence<T> dedup(parlay::sequence<T> const &A) {
  return dedup_impl<T>::apply(A);
}

// Implementation for unsigned integral types
template <class T>
struct dedup_impl<T, std::enable_if_t<std::is_integral_v<T> && std::is_unsigned_v<T>>> {
  static parlay::sequence<T> apply(parlay::sequence<T> const &A) {
    if (A.empty()) {
      return parlay::sequence<T>();
    }

    auto [min_v, max_v] = parlay::minmax_element(A);
    unsigned long long range = static_cast<unsigned long long>(*max_v) - static_cast<unsigned long long>(*min_v);

    // Heuristic for using the atomic bitmap optimization.
    // Use the bitmap if:
    // 1. The memory for the bitmap is not excessive (e.g., < 512 MiB).
    // 2. The range is not excessively sparse compared to the number of elements.
    //    A sparse range would lead to a very large but mostly empty bitmap,
    //    wasting memory and initialization time. The factor of 16 is a heuristic trade-off.
    constexpr size_t max_bitmap_bytes = 512 * 1024 * 1024;
    if ((range + 1) < max_bitmap_bytes && range < static_cast<unsigned long long>(A.size()) * 16) {
      parlay::sequence<std::atomic<bool>> seen(range + 1);
      // Initialize the bitmap in parallel. Using a grain size can improve
      // performance for the parallel_for.
      parlay::parallel_for(0, range + 1, [&](size_t i) {
        seen[i].store(false, std::memory_order_relaxed);
      }, 1024);

      auto min_val = *min_v;
      // Filter the input sequence, keeping only the elements that are seen
      // for the first time. The atomic exchange operation ensures that only
      // one thread will succeed for each unique value.
      return parlay::filter(A, [&](const T& x) {
        return !seen[static_cast<unsigned long long>(x) - min_val].exchange(true, std::memory_order_relaxed);
      });
    } else {
      // Fallback to the default hash-based implementation for sparse ranges.
      return parlay::remove_duplicates(A);
    }
  }
};

// Implementation for signed integral types
template <class T>
struct dedup_impl<T, std::enable_if_t<std::is_integral_v<T> && std::is_signed_v<T>>> {
  static parlay::sequence<T> apply(parlay::sequence<T> const &A) {
    if (A.empty()) {
      return parlay::sequence<T>();
    }
    // To handle signed integers safely and reuse the unsigned implementation,
    // we perform a bitwise conversion to an unsigned type of the same size.
    // This preserves uniqueness and allows for correct range calculations
    // without overflow issues (e.g., max_v - min_v).
    using unsigned_T = parlay::make_unsigned_t<T>;

    auto unsigned_seq = parlay::map(A, [](T x) {
      return parlay::to_unsigned(x);
    });

    // Run the deduplication on the unsigned sequence. This will trigger the
    // unsigned integer specialization.
    auto unsigned_deduped = dedup_impl<unsigned_T>::apply(unsigned_seq);

    // Convert the unique unsigned elements back to their original signed type.
    return parlay::map(unsigned_deduped, [](unsigned_T x) {
      return parlay::to_signed(x);
    });
  }
};

// Generic implementation for all other types (e.g., std::string)
template <class T>
struct dedup_impl<T, std::enable_if_t<!std::is_integral_v<T>>> {
  static parlay::sequence<T> apply(parlay::sequence<T> const &A) {
    // For non-integral types like strings, or for integral types that
    // did not meet the criteria for the bitmap optimization,
    // parlay::remove_duplicates is an excellent, highly-optimized choice.
    // It uses a parallel hash table internally and is expected to be
    // very fast. Beating it would require a custom, specialized hash
    // table which is a complex and risky endeavor.
    return parlay::remove_duplicates(A);
  }
};

