#include "parlay/primitives.h"
#include "parlay/integer_sort.h"
#include <type_traits>

template <class T>
parlay::sequence<T> dedup(parlay::sequence<T> const &A) {
  // This implementation uses a hybrid strategy to achieve the best performance
  // across different data types and distributions. A compile-time check
  // dispatches to the most suitable algorithm.

  // For standard integer types, a sort-based approach using parallel radix sort
  // is often the fastest. Radix sort (parlay::integer_sort) has linear-time
  // complexity and exhibits excellent cache locality due to its streaming memory
  // access patterns. This can outperform the hash-based approach, which has
  // more random memory accesses, especially on inputs with a high number of
  // unique elements (like a uniform random distribution).
  if constexpr (std::is_integral_v<T> && !std::is_same_v<T, bool> && sizeof(T) <= sizeof(unsigned long long)) {
    if (A.empty()) {
      return parlay::sequence<T>();
    }

    // 1. Sort the input sequence using a highly optimized parallel radix sort.
    auto sorted = parlay::integer_sort(A);

    // 2. Identify the first occurrence of each unique element in the sorted sequence.
    // An element at index `i` is the first of its kind if it's the first element
    // of the sequence or differs from the previous one. A `delayed_seq` computes
    // these flags on-the-fly, avoiding the memory overhead of an intermediate flags array.
    auto flags = parlay::delayed_seq<bool>(sorted.size(), [&](size_t i) {
      return (i == 0) || (sorted[i] != sorted[i - 1]);
    });

    // 3. Pack the elements for which the flag is true into the final result sequence.
    // `parlay::pack` is an efficient parallel primitive for this filtering operation.
    return parlay::pack(sorted, flags);
  } else {
    // For all other types (e.g., strings, custom objects) or large/unsupported integers,
    // a hash-based approach is the most robust and generally fastest method.
    // Hashing is typically much faster than comparison for complex types, making
    // the O(n) expected work of the hash-based algorithm superior to an
    // O(n log n) comparison-sort-based one. The hash-based approach is also more
    // memory-efficient when there are many duplicates (e.g., exponential distribution),
    // as the size of the hash table depends on the number of unique elements.
    // `parlay::remove_duplicates` provides a state-of-the-art implementation of this strategy.
    return parlay::remove_duplicates(A);
  }
}
